// ============================================
// Parse Evolution API inbound message
// Filters: own messages, groups, unsupported types
// ============================================

const body = $input.first().json.body || $input.first().json;

const messages = body.data?.messages || body.messages || [];
const message = messages[0] || body.data || body;

const key = message.key || {};
const remoteJid = key.remoteJid || message.remoteJid || '';
const fromMe = key.fromMe || false;
const wamid = key.id || message.id || '';
const pushName = message.pushName || '';
const instanceName = body.instance || body.instanceName || '';

if (fromMe) return [{ json: { ignore: true, reason: 'from_me' } }];
if (remoteJid.includes('@g.us')) return [{ json: { ignore: true, reason: 'group_message' } }];
if (remoteJid === 'status@broadcast') return [{ json: { ignore: true, reason: 'status_broadcast' } }];

const msgContent = message.message || {};
let messageContent = '';
let messageType = 'unsupported';

if (msgContent.conversation) {
  messageContent = msgContent.conversation;
  messageType = 'text';
} else if (msgContent.extendedTextMessage?.text) {
  messageContent = msgContent.extendedTextMessage.text;
  messageType = 'text';
} else if (msgContent.imageMessage?.caption) {
  messageContent = msgContent.imageMessage.caption;
  messageType = 'image';
} else if (msgContent.audioMessage) {
  messageContent = '[Áudio]';
  messageType = 'audio';
} else if (msgContent.documentMessage?.caption) {
  messageContent = msgContent.documentMessage.caption;
  messageType = 'document';
}

if (!messageContent) return [{ json: { ignore: true, reason: 'no_text_content', messageType } }];

// Extract attribution ref code (e.g. "Ref: W8F" or "ref:W8F" or "REF W8F")
let refCode = null;
const refMatch = messageContent.match(/[Rr][Ee][Ff][:\s]+([A-Z0-9]{3})\b/i);
if (refMatch) refCode = refMatch[1].toUpperCase();

return [{
  json: {
    ignore: false,
    remoteJid,
    pushName,
    wamid,
    messageContent,
    messageType,
    instanceName,
    phone: remoteJid.split('@')[0],
    refCode
  }
}];

// Generate available slots: next 3 business days, 9-17h
// Filters already-booked slots from Buscar Config Clínica

const msgData = $('Parse Evolution Payload').first().json;
const clinicData = $('Buscar Config Clínica').first().json;

const clinicId = clinicData?.clinic_id || null;
const bookedSlots = new Set(clinicData?.booked_slots || []);

const slots = [];
let daysAdded = 0;
let checkDate = new Date();
checkDate.setDate(checkDate.getDate() + 1);

while (daysAdded < 3) {
  const dow = checkDate.getDay();
  if (dow !== 0 && dow !== 6) {
    for (let h = 9; h <= 17; h++) {
      const slot = new Date(checkDate);
      slot.setHours(h, 0, 0, 0);
      const y = slot.getFullYear();
      const m = String(slot.getMonth() + 1).padStart(2, '0');
      const d = String(slot.getDate()).padStart(2, '0');
      const hh = String(slot.getHours()).padStart(2, '0');
      const slotStr = `${y}-${m}-${d} ${hh}:00`;
      if (!bookedSlots.has(slotStr)) slots.push(slotStr);
    }
    daysAdded++;
  }
  checkDate.setDate(checkDate.getDate() + 1);
}

return [{ json: { ...msgData, clinicId, availableSlots: slots.slice(0, 3) } }];

// Merge attribution_id from Postgres result back into the main data item
const attrRows = $input.all();
const slotsData = $('Buscar Slots Disponíveis').first().json;

// attribution_id is the resolved UUID (or null for organic contacts)
const attributionId = (attrRows.length > 0 && attrRows[0].json?.attribution_id)
  ? attrRows[0].json.attribution_id
  : null;

return [{
  json: {
    ...slotsData,
    attributionId
  }
}];

// ============================================
// Parse Sofia API v2 response
// Flattens agent_runs into individual messages
// Each message becomes one item in the flow
// ============================================

const response = $input.first().json;
const body = response.body || response;

const agentRuns = body.agent_runs || [];
const requiresHuman = body.requires_human === true;
const conversationStage = body.conversation_stage || 'active';
const traceId = body.trace_id || '';
const language = body.language || 'pt-BR';
const sessionId = body.session_id || '';

// Flatten all messages from all agent_runs preserving order
const allMessages = [];
for (const run of agentRuns) {
  for (const msg of (run.messages || [])) {
    if (msg.content) {
      allMessages.push({
        messageType: msg.type || 'text',
        messageContent: msg.content,
        agentName: run.agent || 'Sofia',
        runData: run.data || null,
      });
    }
  }
}

// No messages — return empty item so flow can still check requires_human
if (allMessages.length === 0) {
  return [{ json: { messageType: 'text', messageContent: '', agentName: 'Sofia', runData: null, requiresHuman, conversationStage, traceId, language, sessionId, skip: true } }];
}

// Return one item per message, each carrying the shared metadata
return allMessages.map(msg => ({
  json: { ...msg, requiresHuman, conversationStage, traceId, language, sessionId, skip: false }
}));

// Detect if Sofia confirmed a new appointment and fire conversion upload
// Runs once against the raw Sofia API response (before fan-out per message)

const response = $('Chamar Sofia API').first().json;
const body = response.body || response;
const agentRuns = body.agent_runs || [];

// Look for a Scheduler run that produced a booked appointment
const bookingRun = agentRuns.find(r => r.data?.type === 'appointment' && r.data?.chosen_slot);
if (!bookingRun) return [];  // no booking — stop this branch silently

const attributionId = $('Merge Attribution Data').first().json.attributionId;
if (!attributionId) return [];  // organic contact — no conversion to upload

const clinicId = $('Merge Attribution Data').first().json.clinicId;

return [{
  json: {
    conversion_type: 'appointment',
    attribution_id: attributionId,
    clinic_id: clinicId,
    service_name: bookingRun.data.service || '',
    scheduled_at: bookingRun.data.chosen_slot,
    conversion_value_brl: 0  // conversion uploader fetches avg_ticket from sf_clinic_profiles
  }
}];
